args.sparql:
SELECT ?duration WHERE {
  ?series wdt:P31 wd:Q1363275 ;
          wdt:P577 ?date ;
          wdt:P4724 ?winner ;
          wdt:P269 ?runner_up .
  FILTER (STRSTARTS(STR(?date), "1977") || STRSTARTS(STR(?date), "1978") || STRSTARTS(STR(?date), "2008") || STRSTARTS(STR(?date), "2009"))
  FILTER ( ( ?winner = wd:Q334634 && ?runner_up = wd:Q650840 ) || ( ?winner = wd:Q650840 && ?runner_up = wd:Q334634 ) )
  ?series p:P1500 ?game .
  ?game wdt:P555 ?duration .
  FILTER (isLiteral(?duration) && datatype(?duration) = xsd:float)
} ORDER BY ASC(?duration) LIMIT 1

